# --- Shared State ---

class _State:
    def __init__(self, now=None):
        self.lock = threading.RLock()
        self.now = now or (lambda: datetime.now(timezone.utc).isoformat())
        self._next_id = 1

        # Stores
        self.users: Dict[int, User] = {}
        self.canvases: Dict[int, Canvas] = {}
        self.elements: Dict[int, DesignElement] = {}
        self.shapes: Dict[int, Shape] = {}
        self.textures: Dict[int, Texture] = {}
        self.groups: Dict[int, ElementGroup] = {}
        self.annotations: Dict[int, Annotation] = {}
        self.events: Dict[int, CanvasEvent] = {}

        # Indexes
        self.username_index: Dict[str, int] = {}
        self.email_index: Dict[str, int] = {}
        self.session_index: Dict[str, int] = {}
        self.canvas_elements: Dict[int, List[int]] = {}
        self.canvas_annotations: Dict[int, List[int]] = {}
        self.element_annotations: Dict[int, List[int]] = {}
        self.canvas_events_index: Dict[int, List[int]] = {}
        self.user_canvases: Dict[int, List[int]] = {}

        # Feature dependency tracking
        self.features: Dict[str, FeatureStatus] = {
            "authentication": FeatureStatus.ACTIVE,
            "canvas": FeatureStatus.NOT_INITIALIZED,
            "shape_tools": FeatureStatus.NOT_INITIALIZED,
            "texture_tools": FeatureStatus.NOT_INITIALIZED,
            "element_management": FeatureStatus.NOT_INITIALIZED,
            "annotations": FeatureStatus.NOT_INITIALIZED,
        }
        self.feature_dependencies: Dict[str, List[str]] = {
            "canvas": ["authentication"],
            "shape_tools": ["canvas"],
            "texture_tools": ["shape_tools"],
            "element_management": ["shape_tools", "texture_tools"],
            "annotations": ["canvas"],
        }

    def next_id(self) -> int:
        val = self._next_id
        self._next_id += 1
        return val


# --- Authentication Service ---

class AuthenticationService:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def _hash_password(self, password: str) -> str:
        return hashlib.sha256(password.encode()).hexdigest()

    def register_user(self, username: str, email: str, password: str,
                      display_name: Optional[str] = None, role: str = "designer") -> User:
        with self._lock:
            if not username or not isinstance(username, str):
                raise ValidationError("Username is required and must be a non-empty string")
            if not email or not isinstance(email, str):
                raise ValidationError("Email is required and must be a non-empty string")
            if not password or not isinstance(password, str):
                raise ValidationError("Password is required and must be a non-empty string")
            if len(password) < 6:
                raise ValidationError("Password must be at least 6 characters")
            if "@" not in email or "." not in email.split("@")[-1]:
                raise ValidationError("Invalid email format")

            username_lower = username.strip().lower()
            email_lower = email.strip().lower()

            if username_lower in self._state.username_index:
                raise DuplicateError(f"Username '{username}' is already taken")
            if email_lower in self._state.email_index:
                raise DuplicateError(f"Email '{email}' is already registered")

            user_id = self._state.next_id()
            user = User(
                id=user_id,
                username=username.strip(),
                email=email.strip(),
                password_hash=self._hash_password(password),
                display_name=display_name or username.strip(),
                created_at=self._state.now(),
                role=role,
            )
            self._state.users[user_id] = user
            self._state.username_index[username_lower] = user_id
            self._state.email_index[email_lower] = user_id
            self._state.user_canvases[user_id] = []
            return user.clone()

    def login(self, username: str, password: str) -> Dict[str, Any]:
        with self._lock:
            if not username or not password:
                raise ValidationError("Username and password are required")

            username_lower = username.strip().lower()
            user_id = self._state.username_index.get(username_lower)
            if user_id is None:
                raise AuthenticationError("Invalid username or password")

            user = self._state.users[user_id]
            if self._hash_password(password) != user.password_hash:
                raise AuthenticationError("Invalid username or password")

            if not user.is_active:
                raise AuthenticationError("Account is deactivated")

            session_token = str(uuid.uuid4())
            user.last_login = self._state.now()
            user.sessions.append(session_token)
            self._state.session_index[session_token] = user_id
            return {
                "user_id": user_id,
                "session_token": session_token,
                "username": user.username,
                "display_name": user.display_name,
            }

    def logout(self, session_token: str) -> bool:
        with self._lock:
            if session_token not in self._state.session_index:
                return False
            user_id = self._state.session_index.pop(session_token)
            user = self._state.users.get(user_id)
            if user and session_token in user.sessions:
                user.sessions.remove(session_token)
            return True

    def get_user(self, user_id: int) -> User:
        with self._lock:
            if user_id not in self._state.users:
                raise NotFoundError(f"User {user_id} not found")
            return self._state.users[user_id].clone()

    def get_user_by_username(self, username: str) -> User:
        with self._lock:
            username_lower = username.strip().lower()
            user_id = self._state.username_index.get(username_lower)
            if user_id is None:
                raise NotFoundError(f"User '{username}' not found")
            return self._state.users[user_id].clone()

    def update_user(self, user_id: int, display_name: Optional[str] = None,
                    email: Optional[str] = None, is_active: Optional[bool] = None) -> User:
        with self._lock:
            if user_id not in self._state.users:
                raise NotFoundError(f"User {user_id} not found")
            user = self._state.users[user_id]

            if email is not None:
                email_lower = email.strip().lower()
                existing = self._state.email_index.get(email_lower)
                if existing is not None and existing != user_id:
                    raise DuplicateError(f"Email '{email}' is already registered")
                old_email_lower = user.email.strip().lower()
                if old_email_lower in self._state.email_index:
                    del self._state.email_index[old_email_lower]
                user.email = email.strip()
                self._state.email_index[email_lower] = user_id

            if display_name is not None:
                user.display_name = display_name

            if is_active is not None:
                user.is_active = is_active

            return user.clone()

    def delete_user(self, user_id: int) -> bool:
        with self._lock:
            if user_id not in self._state.users:
                raise NotFoundError(f"User {user_id} not found")
            user = self._state.users.pop(user_id)
            username_lower = user.username.strip().lower()
            email_lower = user.email.strip().lower()
            self._state.username_index.pop(username_lower, None)
            self._state.email_index.pop(email_lower, None)
            for token in user.sessions:
                self._state.session_index.pop(token, None)
            self._state.user_canvases.pop(user_id, None)
            return True

    def list_users(self) -> List[User]:
        with self._lock:
            return [u.clone() for u in self._state.users.values()]

    def validate_session(self, session_token: str) -> Optional[int]:
        with self._lock:
            return self._state.session_index.get(session_token)

    def _require_auth(self, user_id: int):
        if user_id not in self._state.users:
            raise AuthenticationError(f"User {user_id} is not authenticated")
        if not self._state.users[user_id].is_active:
            raise AuthenticationError(f"User {user_id} account is deactivated")


# --- Canvas Service ---

class CanvasService:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def _check_dependencies(self):
        with self._lock:
            if self._state.features["authentication"] != FeatureStatus.ACTIVE:
                raise DependencyError("Authentication system must be active before using canvas")

    def create_canvas(self, owner_id: int, name: str, width: float = 1920.0,
                      height: float = 1080.0, background_color: str = "#ffffff") -> Canvas:
        with self._lock:
            self._check_dependencies()
            if owner_id not in self._state.users:
                raise NotFoundError(f"User {owner_id} not found")
            if not self._state.users[owner_id].is_active:
                raise AuthorizationError(f"User {owner_id} is not active")
            if not name or not isinstance(name, str):
                raise ValidationError("Canvas name is required")
            if width <= 0 or height <= 0:
                raise ValidationError("Canvas dimensions must be positive")

            canvas_id = self._state.next_id()
            canvas = Canvas(
                id=canvas_id,
                name=name.strip(),
                owner_id=owner_id,
                width=width,
                height=height,
                background_color=background_color,
                created_at=self._state.now(),
                updated_at=self._state.now(),
                collaborators=[owner_id],
            )
            self._state.canvases[canvas_id] = canvas
            self._state.canvas_elements[canvas_id] = []
            self._state.canvas_annotations[canvas_id] = []
            self._state.canvas_events_index[canvas_id] = []
            self._state.user_canvases.setdefault(owner_id, []).append(canvas_id)

            if self._state.features["canvas"] == FeatureStatus.NOT_INITIALIZED:
                self._state.features["canvas"] = FeatureStatus.ACTIVE

            return canvas.clone()

    def get_canvas(self, canvas_id: int) -> Canvas:
        with self._lock:
            if canvas_id not in self._state.canvases:
                raise NotFoundError(f"Canvas {canvas_id} not found")
            return self._state.canvases[canvas_id].clone()

    def update_canvas(self, canvas_id: int, user_id: int, name: Optional[str] = None,
                      width: Optional[float] = None, height: Optional[float] = None,
                      background_color: Optional[str] = None) -> Canvas:
        with self._lock:
            if canvas_id not in self._state.canvases:
                raise NotFoundError(f"Canvas {canvas_id} not found")
            canvas = self._state.canvases[canvas_id]
            if user_id not in canvas.collaborators:
                raise AuthorizationError(f"User {user_id} is not a collaborator on this canvas")

            if name is not None:
                if not name.strip():
                    raise ValidationError("Canvas name cannot be empty")
                canvas.name = name.strip()
            if width is not None:
                if width <= 0:
                    raise ValidationError("Width must be positive")
                canvas.width = width
            if height is not None:
                if height <= 0:
                    raise ValidationError("Height must be positive")
                canvas.height = height
            if background_color is not None:
                canvas.background_color = background_color

            canvas.updated_at = self._state.now()
            canvas.version += 1
            return canvas.clone()

    def delete_canvas(self, canvas_id: int, user_id: int) -> bool:
        with self._lock:
            if canvas_id not in self._state.canvases:
                raise NotFoundError(f"Canvas {canvas_id} not found")
            canvas = self._state.canvases[canvas_id]
            if canvas.owner_id != user_id:
                raise AuthorizationError("Only the canvas owner can delete it")

            # Cascade delete elements
            element_ids = self._state.canvas_elements.pop(canvas_id, [])
            for eid in element_ids:
                self._state.elements.pop(eid, None)
                self._state.element_annotations.pop(eid, None)

            # Cascade delete annotations
            annotation_ids = self._state.canvas_annotations.pop(canvas_id, [])
            for aid in annotation_ids:
                self._state.annotations.pop(aid, None)

            # Cascade delete events
            event_ids = self._state.canvas_events_index.pop(canvas_id, [])
            for evid in event_ids:
                self._state.events.pop(evid, None)

            # Remove from user_canvases
            for uid in canvas.collaborators:
                if uid in self._state.user_canvases:
                    canvases = self._state.user_canvases[uid]
                    if canvas_id in canvases:
                        canvases.remove(canvas_id)

            # Remove groups on this canvas
            to_remove = [gid for gid, g in self._state.groups.items()
                         if g.canvas_id == canvas_id]
            for gid in to_remove:
                del self._state.groups[gid]

            del self._state.canvases[canvas_id]
            return True

    def add_collaborator(self, canvas_id: int, owner_id: int, collaborator_id: int) -> Canvas:
        with self._lock:
            if canvas_id not in self._state.canvases:
                raise NotFoundError(f"Canvas {canvas_id} not found")
            if collaborator_id not in self._state.users:
                raise NotFoundError(f"User {collaborator_id} not found")
            canvas = self._state.canvases[canvas_id]
            if canvas.owner_id != owner_id:
                raise AuthorizationError("Only the canvas owner can add collaborators")
            if collaborator_id in canvas.collaborators:
                raise DuplicateError(f"User {collaborator_id} is already a collaborator")

            canvas.collaborators.append(collaborator_id)
            self._state.user_canvases.setdefault(collaborator_id, []).append(canvas_id)
            canvas.updated_at = self._state.now()
            return canvas.clone()

    def remove_collaborator(self, canvas_id: int, owner_id: int, collaborator_id: int) -> Canvas:
        with self._lock:
            if canvas_id not in self._state.canvases:
                raise NotFoundError(f"Canvas {canvas_id} not found")
            canvas = self._state.canvases[canvas_id]
            if canvas.owner_id != owner_id:
                raise AuthorizationError("Only the canvas owner can remove collaborators")
            if collaborator_id == owner_id:
                raise ValidationError("Cannot remove the canvas owner")
            if collaborator_id not in canvas.collaborators:
                raise NotFoundError(f"User {collaborator_id} is not a collaborator")

            canvas.collaborators.remove(collaborator_id)
            if collaborator_id in self._state.user_canvases:
                canvases = self._state.user_canvases[collaborator_id]
                if canvas_id in canvases:
                    canvases.remove(canvas_id)
            canvas.updated_at = self._state.now()
            return canvas.clone()

    def list_canvases(self, user_id: Optional[int] = None) -> List[Canvas]:
        with self._lock:
            if user_id is not None:
                canvas_ids = self._state.user_canvases.get(user_id, [])
                return [self._state.canvases[cid].clone()
                        for cid in canvas_ids if cid in self._state.canvases]
            return [c.clone() for c in self._state.canvases.values()]

    def record_event(self, canvas_id: int, user_id: int, event_type: str,
                     data: Dict[str, Any]) -> CanvasEvent:
        with self._lock:
            if canvas_id not in self._state.canvases:
                raise NotFoundError(f"Canvas {canvas_id} not found")
            event_id = self._state.next_id()
            event = CanvasEvent(
                id=event_id,
                canvas_id=canvas_id,
                user_id=user_id,
                event_type=event_type,
                data=data,
                timestamp=self._state.now(),
            )
            self._state.events[event_id] = event
            self._state.canvas_events_index.setdefault(canvas_id, []).append(event_id)
            return event.clone()

    def get_canvas_events(self, canvas_id: int, limit: int = 50) -> List[CanvasEvent]:
        with self._lock:
            if canvas_id not in self._state.canvases:
                raise NotFoundError(f"Canvas {canvas_id} not found")
            event_ids = self._state.canvas_events_index.get(canvas_id, [])
            events = [self._state.events[eid].clone()
                      for eid in event_ids if eid in self._state.events]
            return events[-limit:]


# --- Shape and Texture Tools ---

class ShapeToolService:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def _check_dependencies(self):
        if self._state.features["canvas"] != FeatureStatus.ACTIVE:
            raise DependencyError(
                "Canvas must be active before using shape tools")

    def create_shape(self, canvas_id: int, user_id: int, shape_type: str,
                     x: float = 0.0, y: float = 0.0, width: float = 100.0,
                     height: float = 100.0, rotation: float = 0.0,
                     properties: Optional[Dict[str, Any]] = None) -> DesignElement:
        with self._lock:
            self._check_dependencies()
            if canvas_id not in self._state.canvases:
                raise NotFoundError(f"Canvas {canvas_id} not found")
            canvas = self._state.canvases[canvas_id]
            if user_id not in canvas.collaborators:
                raise AuthorizationError(
                    f"User {user_id} is not a collaborator on canvas {canvas_id}")

            valid_types = [st.value for st in ShapeType]
            if shape_type not in valid_types:
                raise ValidationError(
                    f"Invalid shape type '{shape_type}'. Valid: {valid_types}")
            if width <= 0 or height <= 0:
                raise ValidationError("Shape dimensions must be positive")

            shape_id = self._state.next_id()
            position = Point(x=x, y=y)
            z_index = len(self._state.canvas_elements.get(canvas_id, []))

            shape = Shape(
                id=shape_id,
                shape_type=shape_type,
                position=position,
                width=width,
                height=height,
                rotation=rotation,
                z_index=z_index,
                properties=properties or {},
            )
            self._state.shapes[shape_id] = shape

            element_id = self._state.next_id()
            element = DesignElement(
                id=element_id,
                name=f"{shape_type}_{element_id}",
                element_type="shape",
                shape=shape,
                position=position,
                width=width,
                height=height,
                rotation=rotation,
                z_index=z_index,
                owner_id=user_id,
                canvas_id=canvas_id,
                created_at=self._state.now(),
                updated_at=self._state.now(),
                properties=properties or {},
            )
            self._state.elements[element_id] = element
            self._state.canvas_elements.setdefault(canvas_id, []).append(element_id)

            if self._state.features["shape_tools"] == FeatureStatus.NOT_INITIALIZED:
                self._state.features["shape_tools"] = FeatureStatus.ACTIVE

            canvas.updated_at = self._state.now()
            canvas.version += 1
            return element.clone()

    def update_shape(self, element_id: int, user_id: int,
                     x: Optional[float] = None, y: Optional[float] = None,
                     width: Optional[float] = None, height: Optional[float] = None,
                     rotation: Optional[float] = None,
                     properties: Optional[Dict[str, Any]] = None) -> DesignElement:
        with self._lock:
            self._check_dependencies()
            if element_id not in self._state.elements:
                raise NotFoundError(f"Element {element_id} not found")
            element = self._state.elements[element_id]
            if element.element_type != "shape":
                raise ValidationError(f"Element {element_id} is not a shape")
            if element.status == ElementStatus.LOCKED.value and element.locked_by != user_id:
                raise AuthorizationError(f"Element {element_id} is locked by another user")

            canvas = self._state.canvases.get(element.canvas_id)
            if canvas and user_id not in canvas.collaborators:
                raise AuthorizationError(f"User {user_id} is not a collaborator")

            if x is not None:
                element.position.x = x
                if element.shape:
                    element.shape.position.x = x
            if y is not None:
                element.position.y = y
                if element.shape:
                    element.shape.position.y = y
            if width is not None:
                if width <= 0:
                    raise ValidationError("Width must be positive")
                element.width = width
                if element.shape:
                    element.shape.width = width
            if height is not None:
                if height <= 0:
                    raise ValidationError("Height must be positive")
                element.height = height
                if element.shape:
                    element.shape.height = height
            if rotation is not None:
                element.rotation = rotation
                if element.shape:
                    element.shape.rotation = rotation
            if properties is not None:
                element.properties.update(properties)
                if element.shape:
                    element.shape.properties.update(properties)

            element.updated_at = self._state.now()
            return element.clone()

    def delete_shape(self, element_id: int, user_id: int) -> bool:
        with self._lock:
            if element_id not in self._state.elements:
                raise NotFoundError(f"Element {element_id} not found")
            element = self._state.elements[element_id]
            if element.element_type != "shape":
                raise ValidationError(f"Element {element_id} is not a shape")

            canvas = self._state.canvases.get(element.canvas_id)
            if canvas and user_id not in canvas.collaborators:
                raise AuthorizationError(f"User {user_id} is not a collaborator")
            if element.status == ElementStatus.LOCKED.value and element.locked_by != user_id:
                raise AuthorizationError(f"Element {element_id} is locked by another user")

            # Remove from canvas elements
            if element.canvas_id in self._state.canvas_elements:
                elems = self._state.canvas_elements[element.canvas_id]
                if element_id in elems:
                    elems.remove(element_id)

            # Remove from groups
            for group in self._state.groups.values():
                if element_id in group.element_ids:
                    group.element_ids.remove(element_id)

            # Remove associated annotations
            ann_ids = self._state.element_annotations.pop(element_id, [])
            for aid in ann_ids:
                self._state.annotations.pop(aid, None)
                if element.canvas_id in self._state.canvas_annotations:
                    canvas_anns = self._state.canvas_annotations[element.canvas_id]
                    if aid in canvas_anns:
                        canvas_anns.remove(aid)

            # Remove shape
            if element.shape:
                self._state.shapes.pop(element.shape.id, None)

            del self._state.elements[element_id]
            return True

    def get_shape(self, element_id: int) -> DesignElement:
        with self._lock:
            if element_id not in self._state.elements:
                raise NotFoundError(f"Element {element_id} not found")
            element = self._state.elements[element_id]
            if element.element_type != "shape":
                raise ValidationError(f"Element {element_id} is not a shape")
            return element.clone()

    def list_shapes(self, canvas_id: int) -> List[DesignElement]:
        with self._lock:
            if canvas_id not in self._state.canvases:
                raise NotFoundError(f"Canvas {canvas_id} not found")
            element_ids = self._state.canvas_elements.get(canvas_id, [])
            return [self._state.elements[eid].clone()
                    for eid in element_ids
                    if eid in self._state.elements
                    and self._state.elements[eid].element_type == "shape"
                    and self._state.elements[eid].status != ElementStatus.DELETED.value]


class TextureToolService:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def _check_dependencies(self):
        if self._state.features["shape_tools"] != FeatureStatus.ACTIVE:
            raise DependencyError(
                "Shape tools must be active before applying textures")

    def create_texture(self, texture_type: str, color: Optional[str] = None,
                       colors: Optional[List[str]] = None,
                       pattern_name: Optional[str] = None,
                       opacity: float = 1.0,
                       properties: Optional[Dict[str, Any]] = None) -> Texture:
        with self._lock:
            self._check_dependencies()
            valid_types = [tt.value for tt in TextureType]
            if texture_type not in valid_types:
                raise ValidationError(
                    f"Invalid texture type '{texture_type}'. Valid: {valid_types}")
            if opacity < 0.0 or opacity > 1.0:
                raise ValidationError("Opacity must be between 0.0 and 1.0")

            texture_id = self._state.next_id()
            texture = Texture(
                id=texture_id,
                texture_type=texture_type,
                color=color,
                colors=colors or [],
                pattern_name=pattern_name,
                opacity=opacity,
                properties=properties or {},
            )
            self._state.textures[texture_id] = texture

            if self._state.features["texture_tools"] == FeatureStatus.NOT_INITIALIZED:
                self._state.features["texture_tools"] = FeatureStatus.ACTIVE

            return texture.clone()

    def apply_texture(self, element_id: int, texture_id: int, user_id: int) -> DesignElement:
        with self._lock:
            self._check_dependencies()
            if element_id not in self._state.elements:
                raise NotFoundError(f"Element {element_id} not found")
            if texture_id not in self._state.textures:
                raise NotFoundError(f"Texture {texture_id} not found")

            element = self._state.elements[element_id]
            if element.element_type != "shape":
                raise ValidationError("Textures can only be applied to shapes")

            canvas = self._state.canvases.get(element.canvas_id)
            if canvas and user_id not in canvas.collaborators:
                raise AuthorizationError(f"User {user_id} is not a collaborator")
            if element.status == ElementStatus.LOCKED.value and element.locked_by != user_id:
                raise AuthorizationError(f"Element {element_id} is locked")

            texture = self._state.textures[texture_id]
            if element.shape:
                element.shape.texture = copy.deepcopy(texture)
            element.updated_at = self._state.now()
            return element.clone()

    def remove_texture(self, element_id: int, user_id: int) -> DesignElement:
        with self._lock:
            if element_id not in self._state.elements:
                raise NotFoundError(f"Element {element_id} not found")
            element = self._state.elements[element_id]
            if element.element_type != "shape":
                raise ValidationError("Only shapes have textures")

            canvas = self._state.canvases.get(element.canvas_id)
            if canvas and user_id not in canvas.collaborators:
                raise AuthorizationError(f"User {user_id} is not a collaborator")

            if element.shape:
                element.shape.texture = None
            element.updated_at = self._state.now()
            return element.clone()

    def get_texture(self, texture_id: int) -> Texture:
        with self._lock:
            if texture_id not in self._state.textures:
                raise NotFoundError(f"Texture {texture_id} not found")
            return self._state.textures[texture_id].clone()

    def list_textures(self) -> List[Texture]:
        with self._lock:
            return [t.clone() for t in self._state.textures.values()]

    def update_texture(self, texture_id: int, color: Optional[str] = None,
                       colors: Optional[List[str]] = None,
                       opacity: Optional[float] = None,
                       properties: Optional[Dict[str, Any]] = None) -> Texture:
        with self._lock:
            if texture_id not in self._state.textures:
                raise NotFoundError(f"Texture {texture_id} not found")
            texture = self._state.textures[texture_id]
            if color is not None:
                texture.color = color
            if colors is not None:
                texture.colors = colors
            if opacity is not None:
                if opacity < 0.0 or opacity > 1.0:
                    raise ValidationError("Opacity must be between 0.0 and 1.0")
                texture.opacity = opacity
            if properties is not None:
                texture.properties.update(properties)
            return texture.clone()

    def delete_texture(self, texture_id: int) -> bool:
        with self._lock:
            if texture_id not in self._state.textures:
                raise NotFoundError(f"Texture {texture_id} not found")
            # Remove from any shapes using it
            texture = self._state.textures[texture_id]
            for element in self._state.elements.values():
                if (element.shape and element.shape.texture
                        and element.shape.texture.id == texture_id):
                    element.shape.texture = None
            del self._state.textures[texture_id]
            return True


