class ElementManagementService:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def _check_dependencies(self):
        if self._state.features["shape_tools"] != FeatureStatus.ACTIVE:
            raise DependencyError(
                "Shape tools must be active before managing elements")

    def align_elements(self, element_ids: List[int], alignment: str,
                       user_id: int) -> List[DesignElement]:
        with self._lock:
            self._check_dependencies()
            if not element_ids:
                raise ValidationError("At least one element ID is required")

            valid_alignments = [a.value for a in AlignmentType]
            if alignment not in valid_alignments:
                raise ValidationError(
                    f"Invalid alignment '{alignment}'. Valid: {valid_alignments}")

            elements = []
            for eid in element_ids:
                if eid not in self._state.elements:
                    raise NotFoundError(f"Element {eid} not found")
                elements.append(self._state.elements[eid])

            # Check authorization
            for el in elements:
                canvas = self._state.canvases.get(el.canvas_id)
                if canvas and user_id not in canvas.collaborators:
                    raise AuthorizationError(
                        f"User {user_id} is not a collaborator on canvas {el.canvas_id}")

            if len(elements) < 2:
                return [el.clone() for el in elements]

            # Calculate alignment reference
            if alignment == AlignmentType.LEFT.value:
                ref = min(el.position.x for el in elements if el.position)
                for el in elements:
                    if el.position:
                        el.position.x = ref
                        if el.shape:
                            el.shape.position.x = ref
            elif alignment == AlignmentType.RIGHT.value:
                ref = max(el.position.x + el.width for el in elements if el.position)
                for el in elements:
                    if el.position:
                        el.position.x = ref - el.width
                        if el.shape:
                            el.shape.position.x = ref - el.width
            elif alignment == AlignmentType.CENTER.value:
                centers = [el.position.x + el.width / 2 for el in elements if el.position]
                ref = sum(centers) / len(centers)
                for el in elements:
                    if el.position:
                        el.position.x = ref - el.width / 2
                        if el.shape:
                            el.shape.position.x = ref - el.width / 2
            elif alignment == AlignmentType.TOP.value:
                ref = min(el.position.y for el in elements if el.position)
                for el in elements:
                    if el.position:
                        el.position.y = ref
                        if el.shape:
                            el.shape.position.y = ref
            elif alignment == AlignmentType.BOTTOM.value:
                ref = max(el.position.y + el.height for el in elements if el.position)
                for el in elements:
                    if el.position:
                        el.position.y = ref - el.height
                        if el.shape:
                            el.shape.position.y = ref - el.height
            elif alignment == AlignmentType.MIDDLE.value:
                centers = [el.position.y + el.height / 2 for el in elements if el.position]
                ref = sum(centers) / len(centers)
                for el in elements:
                    if el.position:
                        el.position.y = ref - el.height / 2
                        if el.shape:
                            el.shape.position.y = ref - el.height / 2

            for el in elements:
                el.updated_at = self._state.now()

            if self._state.features["element_management"] == FeatureStatus.NOT_INITIALIZED:
                self._state.features["element_management"] = FeatureStatus.ACTIVE

            return [el.clone() for el in elements]

    def group_elements(self, element_ids: List[int], group_name: str,
                       user_id: int, canvas_id: int) -> ElementGroup:
        with self._lock:
            self._check_dependencies()
            if not element_ids:
                raise ValidationError("At least one element ID is required")
            if not group_name or not isinstance(group_name, str):
                raise ValidationError("Group name is required")
            if canvas_id not in self._state.canvases:
                raise NotFoundError(f"Canvas {canvas_id} not found")
            canvas = self._state.canvases[canvas_id]
            if user_id not in canvas.collaborators:
                raise AuthorizationError(
                    f"User {user_id} is not a collaborator")

            for eid in element_ids:
                if eid not in self._state.elements:
                    raise NotFoundError(f"Element {eid} not found")
                el = self._state.elements[eid]
                if el.canvas_id != canvas_id:
                    raise ValidationError(
                        f"Element {eid} is not on canvas {canvas_id}")
                if el.group_id is not None:
                    raise ValidationError(
                        f"Element {eid} is already in a group")

            group_id = self._state.next_id()
            group = ElementGroup(
                id=group_id,
                name=group_name.strip(),
                element_ids=list(element_ids),
                canvas_id=canvas_id,
                created_by=user_id,
                created_at=self._state.now(),
            )
            self._state.groups[group_id] = group

            for eid in element_ids:
                self._state.elements[eid].group_id = group_id

            if self._state.features["element_management"] == FeatureStatus.NOT_INITIALIZED:
                self._state.features["element_management"] = FeatureStatus.ACTIVE

            return group.clone()

    def ungroup_elements(self, group_id: int, user_id: int) -> List[DesignElement]:
        with self._lock:
            if group_id not in self._state.groups:
                raise NotFoundError(f"Group {group_id} not found")
            group = self._state.groups[group_id]

            canvas = self._state.canvases.get(group.canvas_id)
            if canvas and user_id not in canvas.collaborators:
                raise AuthorizationError(f"User {user_id} is not a collaborator")

            elements = []
            for eid in group.element_ids:
                if eid in self._state.elements:
                    el = self._state.elements[eid]
                    el.group_id = None
                    elements.append(el)

            del self._state.groups[group_id]
            return [el.clone() for el in elements]

    def arrange_element(self, element_id: int, order: str, user_id: int) -> DesignElement:
        with self._lock:
            self._check_dependencies()
            if element_id not in self._state.elements:
                raise NotFoundError(f"Element {element_id} not found")

            valid_orders = [a.value for a in ArrangementOrder]
            if order not in valid_orders:
                raise ValidationError(
                    f"Invalid arrangement order '{order}'. Valid: {valid_orders}")

            element = self._state.elements[element_id]
            canvas = self._state.canvases.get(element.canvas_id)
            if canvas and user_id not in canvas.collaborators:
                raise AuthorizationError(f"User {user_id} is not a collaborator")

            canvas_element_ids = self._state.canvas_elements.get(element.canvas_id, [])
            canvas_elements = [self._state.elements[eid]
                               for eid in canvas_element_ids
                               if eid in self._state.elements]

            if not canvas_elements:
                return element.clone()

            max_z = max(el.z_index for el in canvas_elements)
            min_z = min(el.z_index for el in canvas_elements)

            if order == ArrangementOrder.BRING_TO_FRONT.value:
                element.z_index = max_z + 1
            elif order == ArrangementOrder.SEND_TO_BACK.value:
                element.z_index = min_z - 1
            elif order == ArrangementOrder.BRING_FORWARD.value:
                element.z_index += 1
            elif order == ArrangementOrder.SEND_BACKWARD.value:
                element.z_index -= 1

            if element.shape:
                element.shape.z_index = element.z_index
            element.updated_at = self._state.now()
            return element.clone()

    def lock_element(self, element_id: int, user_id: int) -> DesignElement:
        with self._lock:
            if element_id not in self._state.elements:
                raise NotFoundError(f"Element {element_id} not found")
            element = self._state.elements[element_id]
            if element.status == ElementStatus.LOCKED.value:
                if element.locked_by == user_id:
                    return element.clone()
                raise AuthorizationError(
                    f"Element {element_id} is already locked by another user")

            canvas = self._state.canvases.get(element.canvas_id)
            if canvas and user_id not in canvas.collaborators:
                raise AuthorizationError(f"User {user_id} is not a collaborator")

            element.status = ElementStatus.LOCKED.value
            element.locked_by = user_id
            element.updated_at = self._state.now()
            return element.clone()

    def unlock_element(self, element_id: int, user_id: int) -> DesignElement:
        with self._lock:
            if element_id not in self._state.elements:
                raise NotFoundError(f"Element {element_id} not found")
            element = self._state.elements[element_id]
            if element.status != ElementStatus.LOCKED.value:
                return element.clone()
            if element.locked_by != user_id:
                # Owner can also unlock
                canvas = self._state.canvases.get(element.canvas_id)
                if canvas and canvas.owner_id != user_id:
                    raise AuthorizationError(
                        "Only the lock holder or canvas owner can unlock")

            element.status = ElementStatus.ACTIVE.value
            element.locked_by = None
            element.updated_at = self._state.now()
            return element.clone()

    def hide_element(self, element_id: int, user_id: int) -> DesignElement:
        with self._lock:
            if element_id not in self._state.elements:
                raise NotFoundError(f"Element {element_id} not found")
            element = self._state.elements[element_id]
            canvas = self._state.canvases.get(element.canvas_id)
            if canvas and user_id not in canvas.collaborators:
                raise AuthorizationError(f"User {user_id} is not a collaborator")
            element.status = ElementStatus.HIDDEN.value
            element.updated_at = self._state.now()
            return element.clone()

    def show_element(self, element_id: int, user_id: int) -> DesignElement:
        with self._lock:
            if element_id not in self._state.elements:
                raise NotFoundError(f"Element {element_id} not found")
            element = self._state.elements[element_id]
            canvas = self._state.canvases.get(element.canvas_id)
            if canvas and user_id not in canvas.collaborators:
                raise AuthorizationError(f"User {user_id} is not a collaborator")
            element.status = ElementStatus.ACTIVE.value
            element.updated_at = self._state.now()
            return element.clone()

    def get_element(self, element_id: int) -> DesignElement:
        with self._lock:
            if element_id not in self._state.elements:
                raise NotFoundError(f"Element {element_id} not found")
            return self._state.elements[element_id].clone()

    def list_elements(self, canvas_id: int,
                      include_hidden: bool = False) -> List[DesignElement]:
        with self._lock:
            if canvas_id not in self._state.canvases:
                raise NotFoundError(f"Canvas {canvas_id} not found")
            element_ids = self._state.canvas_elements.get(canvas_id, [])
            results = []
            for eid in element_ids:
                if eid not in self._state.elements:
                    continue
                el = self._state.elements[eid]
                if el.status == ElementStatus.DELETED.value:
                    continue
                if not include_hidden and el.status == ElementStatus.HIDDEN.value:
                    continue
                results.append(el.clone())
            return results

    def get_group(self, group_id: int) -> ElementGroup:
        with self._lock:
            if group_id not in self._state.groups:
                raise NotFoundError(f"Group {group_id} not found")
            return self._state.groups[group_id].clone()

    def list_groups(self, canvas_id: int) -> List[ElementGroup]:
        with self._lock:
            if canvas_id not in self._state.canvases:
                raise NotFoundError(f"Canvas {canvas_id} not found")
            return [g.clone() for g in self._state.groups.values()
                    if g.canvas_id == canvas_id]


# --- Annotation and Commenting Service ---

class AnnotationService:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def _check_dependencies(self):
        if self._state.features["canvas"] != FeatureStatus.ACTIVE:
            raise DependencyError(
                "Canvas must be active before using annotations")

    def create_annotation(self, canvas_id: int, author_id: int, content: str,
                          annotation_type: str = AnnotationType.NOTE.value,
                          element_id: Optional[int] = None,
                          x: float = 0.0, y: float = 0.0) -> Annotation:
        with self._lock:
            self._check_dependencies()
            if canvas_id not in self._state.canvases:
                raise NotFoundError(f"Canvas {canvas_id} not found")
            if author_id not in self._state.users:
                raise NotFoundError(f"User {author_id} not found")

            canvas = self._state.canvases[canvas_id]
            if author_id not in canvas.collaborators:
                raise AuthorizationError(
                    f"User {author_id} is not a collaborator on canvas {canvas_id}")

            if not content or not isinstance(content, str):
                raise ValidationError("Annotation content is required")

            valid_types = [at.value for at in AnnotationType]
            if annotation_type not in valid_types:
                raise ValidationError(
                    f"Invalid annotation type '{annotation_type}'. Valid: {valid_types}")

            if element_id is not None:
                if element_id not in self._state.elements:
                    raise NotFoundError(f"Element {element_id} not found")
                el = self._state.elements[element_id]
                if el.canvas_id != canvas_id:
                    raise ValidationError(
                        f"Element {element_id} is not on canvas {canvas_id}")

            annotation_id = self._state.next_id()
            annotation = Annotation(
                id=annotation_id,
                element_id=element_id,
                canvas_id=canvas_id,
                author_id=author_id,
                annotation_type=annotation_type,
                content=content.strip(),
                position=Point(x=x, y=y),
                created_at=self._state.now(),
                updated_at=self._state.now(),
            )
            self._state.annotations[annotation_id] = annotation
            self._state.canvas_annotations.setdefault(canvas_id, []).append(annotation_id)
            if element_id is not None:
                self._state.element_annotations.setdefault(element_id, []).append(annotation_id)

            if self._state.features["annotations"] == FeatureStatus.NOT_INITIALIZED:
                self._state.features["annotations"] = FeatureStatus.ACTIVE

            return annotation.clone()

    def update_annotation(self, annotation_id: int, user_id: int,
                          content: Optional[str] = None,
                          annotation_type: Optional[str] = None,
                          resolved: Optional[bool] = None) -> Annotation:
        with self._lock:
            if annotation_id not in self._state.annotations:
                raise NotFoundError(f"Annotation {annotation_id} not found")
            annotation = self._state.annotations[annotation_id]
            if annotation.author_id != user_id:
                canvas = self._state.canvases.get(annotation.canvas_id)
                if not canvas or canvas.owner_id != user_id:
                    raise AuthorizationError(
                        "Only the author or canvas owner can update annotations")

            if content is not None:
                if not content.strip():
                    raise ValidationError("Content cannot be empty")
                annotation.content = content.strip()
            if annotation_type is not None:
                valid_types = [at.value for at in AnnotationType]
                if annotation_type not in valid_types:
                    raise ValidationError(f"Invalid annotation type '{annotation_type}'")
                annotation.annotation_type = annotation_type
            if resolved is not None:
                annotation.resolved = resolved

            annotation.updated_at = self._state.now()
            return annotation.clone()

    def delete_annotation(self, annotation_id: int, user_id: int) -> bool:
        with self._lock:
            if annotation_id not in self._state.annotations:
                raise NotFoundError(f"Annotation {annotation_id} not found")
            annotation = self._state.annotations[annotation_id]
            if annotation.author_id != user_id:
                canvas = self._state.canvases.get(annotation.canvas_id)
                if not canvas or canvas.owner_id != user_id:
                    raise AuthorizationError(
                        "Only the author or canvas owner can delete annotations")

            # Remove from indexes
            if annotation.canvas_id in self._state.canvas_annotations:
                anns = self._state.canvas_annotations[annotation.canvas_id]
                if annotation_id in anns:
                    anns.remove(annotation_id)
            if annotation.element_id is not None:
                if annotation.element_id in self._state.element_annotations:
                    anns = self._state.element_annotations[annotation.element_id]
                    if annotation_id in anns:
                        anns.remove(annotation_id)

            del self._state.annotations[annotation_id]
            return True

    def reply_to_annotation(self, annotation_id: int, user_id: int,
                            content: str) -> Annotation:
        with self._lock:
            if annotation_id not in self._state.annotations:
                raise NotFoundError(f"Annotation {annotation_id} not found")
            if user_id not in self._state.users:
                raise NotFoundError(f"User {user_id} not found")
            if not content or not isinstance(content, str):
                raise ValidationError("Reply content is required")

            annotation = self._state.annotations[annotation_id]
            canvas = self._state.canvases.get(annotation.canvas_id)
            if canvas and user_id not in canvas.collaborators:
                raise AuthorizationError(f"User {user_id} is not a collaborator")

            reply = {
                "id": self._state.next_id(),
                "author_id": user_id,
                "content": content.strip(),
                "created_at": self._state.now(),
            }
            annotation.replies.append(reply)
            annotation.updated_at = self._state.now()
            return annotation.clone()

    def get_annotation(self, annotation_id: int) -> Annotation:
        with self._lock:
            if annotation_id not in self._state.annotations:
                raise NotFoundError(f"Annotation {annotation_id} not found")
            return self._state.annotations[annotation_id].clone()

    def list_annotations(self, canvas_id: int,
                         element_id: Optional[int] = None,
                         include_resolved: bool = True) -> List[Annotation]:
        with self._lock:
            if canvas_id not in self._state.canvases:
                raise NotFoundError(f"Canvas {canvas_id} not found")

            if element_id is not None:
                ann_ids = self._state.element_annotations.get(element_id, [])
            else:
                ann_ids = self._state.canvas_annotations.get(canvas_id, [])

            results = []
            for aid in ann_ids:
                if aid not in self._state.annotations:
                    continue
                ann = self._state.annotations[aid]
                if not include_resolved and ann.resolved:
                    continue
                results.append(ann.clone())
            return results


