class DependencyManagementService:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def get_feature_status(self, feature_name: str) -> FeatureStatus:
        with self._lock:
            if feature_name not in self._state.features:
                raise NotFoundError(f"Feature '{feature_name}' not found")
            return self._state.features[feature_name]

    def get_all_feature_statuses(self) -> Dict[str, str]:
        with self._lock:
            return {k: v.value for k, v in self._state.features.items()}

    def get_feature_dependencies(self, feature_name: str) -> List[str]:
        with self._lock:
            if feature_name not in self._state.features:
                raise NotFoundError(f"Feature '{feature_name}' not found")
            return list(self._state.feature_dependencies.get(feature_name, []))

    def check_dependencies_met(self, feature_name: str) -> bool:
        with self._lock:
            if feature_name not in self._state.features:
                raise NotFoundError(f"Feature '{feature_name}' not found")
            deps = self._state.feature_dependencies.get(feature_name, [])
            for dep in deps:
                if self._state.features.get(dep) != FeatureStatus.ACTIVE:
                    return False
            return True

    def get_unmet_dependencies(self, feature_name: str) -> List[str]:
        with self._lock:
            if feature_name not in self._state.features:
                raise NotFoundError(f"Feature '{feature_name}' not found")
            deps = self._state.feature_dependencies.get(feature_name, [])
            return [d for d in deps
                    if self._state.features.get(d) != FeatureStatus.ACTIVE]

    def activate_feature(self, feature_name: str) -> bool:
        with self._lock:
            if feature_name not in self._state.features:
                raise NotFoundError(f"Feature '{feature_name}' not found")
            deps = self._state.feature_dependencies.get(feature_name, [])
            for dep in deps:
                if self._state.features.get(dep) != FeatureStatus.ACTIVE:
                    raise DependencyError(
                        f"Cannot activate '{feature_name}': "
                        f"dependency '{dep}' is not active")
            self._state.features[feature_name] = FeatureStatus.ACTIVE
            return True

    def deactivate_feature(self, feature_name: str) -> bool:
        with self._lock:
            if feature_name not in self._state.features:
                raise NotFoundError(f"Feature '{feature_name}' not found")
            # Check if any active feature depends on this one
            for fname, deps in self._state.feature_dependencies.items():
                if feature_name in deps:
                    if self._state.features.get(fname) == FeatureStatus.ACTIVE:
                        raise DependencyError(
                            f"Cannot deactivate '{feature_name}': "
                            f"feature '{fname}' depends on it")
            self._state.features[feature_name] = FeatureStatus.DISABLED
            return True

    def get_dependency_graph(self) -> Dict[str, List[str]]:
        with self._lock:
            return copy.deepcopy(self._state.feature_dependencies)

    def get_activation_order(self) -> List[str]:
        """Returns features in topological order for activation."""
        with self._lock:
            visited = set()
            order = []

            def visit(feature):
                if feature in visited:
                    return
                visited.add(feature)
                for dep in self._state.feature_dependencies.get(feature, []):
                    visit(dep)
                order.append(feature)

            for feature in self._state.features:
                visit(feature)
            return order


# --- Main Application ---

class CollaborativeDesignSuite:
    def __init__(self, now=None):
        self._state = _State(now=now)
        self._lock = self._state.lock

        # Services
        self.auth = AuthenticationService(self._state)
        self.canvas = CanvasService(self._state)
        self.shapes = ShapeToolService(self._state)
        self.textures = TextureToolService(self._state)
        self.elements = ElementManagementService(self._state)
        self.annotations = AnnotationService(self._state)
        self.dependencies = DependencyManagementService(self._state)

    @property
    def lock(self):
        return self._lock

    def get_feature_status(self, feature_name: str) -> str:
        return self.dependencies.get_feature_status(feature_name).value

    def get_all_features(self) -> Dict[str, str]:
        return self.dependencies.get_all_feature_statuses()

    def get_canvas_summary(self, canvas_id: int) -> Dict[str, Any]:
        with self._lock:
            if canvas_id not in self._state.canvases:
                raise NotFoundError(f"Canvas {canvas_id} not found")
            canvas = self._state.canvases[canvas_id]
            element_ids = self._state.canvas_elements.get(canvas_id, [])
            annotation_ids = self._state.canvas_annotations.get(canvas_id, [])
            groups = [g for g in self._state.groups.values()
                      if g.canvas_id == canvas_id]
            return {
                "canvas_id": canvas_id,
                "name": canvas.name,
                "owner_id": canvas.owner_id,
                "collaborators": list(canvas.collaborators),
                "element_count": len(element_ids),
                "annotation_count": len(annotation_ids),
                "group_count": len(groups),
                "version": canvas.version,
                "created_at": canvas.created_at,
                "updated_at": canvas.updated_at,
            }

    def get_user_activity(self, user_id: int) -> Dict[str, Any]:
        with self._lock:
            if user_id not in self._state.users:
                raise NotFoundError(f"User {user_id} not found")
            user = self._state.users[user_id]
            canvas_ids = self._state.user_canvases.get(user_id, [])
            elements_created = sum(
                1 for el in self._state.elements.values()
                if el.owner_id == user_id)
            annotations_made = sum(
                1 for ann in self._state.annotations.values()
                if ann.author_id == user_id)
            return {
                "user_id": user_id,
                "username": user.username,
                "canvases_count": len(canvas_ids),
                "elements_created": elements_created,
                "annotations_made": annotations_made,
                "last_login": user.last_login,
            }

    def export_canvas(self, canvas_id: int, format: str = "json") -> str:
        with self._lock:
            if canvas_id not in self._state.canvases:
                raise NotFoundError(f"Canvas {canvas_id} not found")

            canvas = self._state.canvases[canvas_id]
            element_ids = self._state.canvas_elements.get(canvas_id, [])
            elements = []
            for eid in element_ids:
                if eid in self._state.elements:
                    el = self._state.elements[eid]
                    elements.append({
                        "id": el.id,
                        "name": el.name,
                        "type": el.element_type,
                        "position": {"x": el.position.x, "y": el.position.y}
                        if el.position else None,
                        "width": el.width,
                        "height": el.height,
                        "rotation": el.rotation,
                        "z_index": el.z_index,
                        "status": el.status,
                    })

            annotation_ids = self._state.canvas_annotations.get(canvas_id, [])
            annotations = []
            for aid in annotation_ids:
                if aid in self._state.annotations:
                    ann = self._state.annotations[aid]
                    annotations.append({
                        "id": ann.id,
                        "type": ann.annotation_type,
                        "content": ann.content,
                        "author_id": ann.author_id,
                        "element_id": ann.element_id,
                        "resolved": ann.resolved,
                    })

            export_data = {
                "canvas": {
                    "id": canvas.id,
                    "name": canvas.name,
                    "width": canvas.width,
                    "height": canvas.height,
                    "background_color": canvas.background_color,
                    "owner_id": canvas.owner_id,
                    "collaborators": canvas.collaborators,
                    "version": canvas.version,
                },
                "elements": elements,
                "annotations": annotations,
            }

            if format == "json":
                return json.dumps(export_data, indent=2)
            else:
                raise ValidationError(f"Unsupported export format: {format}")


